"use strict";parserFactory.register("readlightnovel.cc",()=>new ReadLightNovelCcParser);class ReadLightNovelCcParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("a.chapter-item")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("section.section")}extractTitleImpl(e){return e.querySelector("div.book-name").textContent}extractAuthor(e){let t=e.querySelector("div.author span.name");return null===t?super.extractAuthor(e):t.textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.book-img")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.synopsis")]}}